-- Insert 50 neural training exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Cross-Crawl Dead Bug', 'cross-crawl-dead-bug', 'Cross-Crawl Dead Bug is a neural-focused drill for cross-body coordination, anterior core timing, and low-threat neural organization. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Supine contralateral drill that links breathing, trunk control, and opposite-limb timing without impact.', 'Primary subrole: Activate. Neural emphasis: cross-body coordination, anterior core timing, and low-threat neural organization. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Cross-body coordination', 'prepare_and_access', 'activate', 'neural_activation', '{"primary_joint_actions":["trunk_bracing","rib_pelvis_stack"],"primary_tissues":["abdominals","obliques","diaphragm","glutes","hip_flexors","adductors","spinal_stabilizers"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"stable","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Perform Cross-Crawl Dead Bug as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Use a mat or clear floor area.","Athlete starts in the base position with ribs stacked over pelvis.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete sets the trunk first and breathes without bracing aggressively.","Move one limb or opposite limbs while the pelvis and ribcage stay quiet.","Pause briefly to show control before the next switch or tap.","End the set when hips rock, breath holding appears, or timing slows."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Ribs stacked over pelvis.","Move the limb without moving the trunk."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Holding breath to create fake stability.","Rib flare, hip shift, or spinal sag."]}'::jsonb),
  ('Bear Crawl Contralateral Tap', 'bear-crawl-contralateral-tap', 'Bear Crawl Contralateral Tap is a neural-focused drill for anti-rotation, contralateral timing, and reflexive trunk stability. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Bear-position tap drill that teaches trunk control while the opposite hand and knee coordinate under light tension.', 'Primary subrole: Activate. Neural emphasis: anti-rotation, contralateral timing, and reflexive trunk stability. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Cross-body coordination', 'prepare_and_access', 'activate', 'neural_activation', '{"primary_joint_actions":["hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination","trunk_bracing","rib_pelvis_stack"],"primary_tissues":["abdominals","obliques","diaphragm","deltoids","rotator_cuff","scapular_stabilizers","glutes","hip_flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"dynamic","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Perform Bear Crawl Contralateral Tap as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Use a mat or clear floor area.","Athlete starts in the base position with ribs stacked over pelvis.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete sets the trunk first and breathes without bracing aggressively.","Move one limb or opposite limbs while the pelvis and ribcage stay quiet.","Pause briefly to show control before the next switch or tap.","End the set when hips rock, breath holding appears, or timing slows."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Ribs stacked over pelvis."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily.","Holding breath to create fake stability.","Rib flare, hip shift, or spinal sag."]}'::jsonb),
  ('Wall Drive Iso Hold', 'wall-drive-iso-hold', 'Wall Drive Iso Hold is a neural-focused drill for acceleration posture, stance stiffness, and neural priming for sprint mechanics. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Low-fatigue wall-drive position hold that teaches shin angle, trunk line, and front-side sprint posture.', 'Primary subrole: Activate. Neural emphasis: acceleration posture, stance stiffness, and neural priming for sprint mechanics. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Acceleration posture activation', 'prepare_and_access', 'activate', 'sprint_activation', '{"primary_joint_actions":["hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination","trunk_bracing","rib_pelvis_stack"],"primary_tissues":["foot_intrinsics","plantar fascia","calves","achilles_tendon","glutes","hip_flexors","adductors","abdominals"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"dynamic","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Perform Wall Drive Iso Hold as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Stand facing a wall with hands on the wall at shoulder height.","Step back until the body can form a straight sprint-posture line.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete starts organized and attentive.","Perform the pattern at the assigned rhythm or speed.","Own the finish position before the next repetition.","Stop before fatigue changes timing, posture, or coordination."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Ribs stacked over pelvis."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily.","Holding breath to create fake stability.","Rib flare, hip shift, or spinal sag."]}'::jsonb),
  ('Wall Drive Switch', 'wall-drive-switch', 'Wall Drive Switch is a neural-focused drill for limb exchange speed, acceleration posture, and elastic switch timing. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Wall-supported knee-drive switch that links sprint posture with quick limb exchange before higher-speed work.', 'Primary subrole: Activate. Neural emphasis: limb exchange speed, acceleration posture, and elastic switch timing. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Acceleration posture activation', 'prepare_and_access', 'activate', 'sprint_activation', '{"primary_joint_actions":["hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination","trunk_bracing","rib_pelvis_stack"],"primary_tissues":["foot_intrinsics","plantar fascia","calves","achilles_tendon","glutes","hip_flexors","adductors","abdominals"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"dynamic","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Perform Wall Drive Switch as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Stand facing a wall with hands on the wall at shoulder height.","Step back until the body can form a straight sprint-posture line.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete starts organized and attentive.","Perform the pattern at the assigned rhythm or speed.","Own the finish position before the next repetition.","Stop before fatigue changes timing, posture, or coordination."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Ribs stacked over pelvis."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily.","Holding breath to create fake stability.","Rib flare, hip shift, or spinal sag."]}'::jsonb),
  ('Push-Up Shoulder Tap Metronome', 'push-up-shoulder-tap-metronome', 'Push-Up Shoulder Tap Metronome is a neural-focused drill for rhythm, shoulder stability, and trunk anti-rotation. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Metronome-paced shoulder tap drill that trains anti-rotation and timing under upper-body support.', 'Primary subrole: Activate. Neural emphasis: rhythm, shoulder stability, and trunk anti-rotation. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Reflexive trunk control', 'prepare_and_access', 'activate', 'neural_activation', '{"primary_joint_actions":["shoulder_support","elbow_extension","scapular_control","trunk_bracing","rib_pelvis_stack"],"primary_tissues":["abdominals","obliques","diaphragm","deltoids","rotator_cuff","scapular_stabilizers","wrist_flexors","wrist_extensors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"stable","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Perform Push-Up Shoulder Tap Metronome as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Use a mat or clear floor area.","Athlete starts in the base position with ribs stacked over pelvis.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete sets the trunk first and breathes without bracing aggressively.","Move one limb or opposite limbs while the pelvis and ribcage stay quiet.","Pause briefly to show control before the next switch or tap.","End the set when hips rock, breath holding appears, or timing slows."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Ribs stacked over pelvis.","Move the limb without moving the trunk."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Holding breath to create fake stability.","Rib flare, hip shift, or spinal sag."]}'::jsonb),
  ('Plank Command Tap Matrix', 'plank-command-tap-matrix', 'Plank Command Tap Matrix is a neural-focused drill for auditory processing, limb dissociation, and anti-rotation under command. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Coach-called plank tap drill that adds fast decision-making to a stable trunk position.', 'Primary subrole: Activate. Neural emphasis: auditory processing, limb dissociation, and anti-rotation under command. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Reactive trunk control', 'prepare_and_access', 'activate', 'neural_activation', '{"primary_joint_actions":["shoulder_support","elbow_extension","scapular_control","trunk_bracing","rib_pelvis_stack"],"primary_tissues":["abdominals","obliques","diaphragm","deltoids","rotator_cuff","scapular_stabilizers","wrist_flexors","wrist_extensors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"stable","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Perform Plank Command Tap Matrix as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Partner or coach stands where the cue is visible or audible without crowding the athlete.","Agree on the cue and stop rule before the first rep.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete holds the start position and waits for the cue instead of guessing.","Coach or partner gives one clear visual or auditory cue.","Athlete makes the correct first movement, finishes the required action, and regains control.","Reset fully before the next rep so attention and mechanics stay crisp."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Ribs stacked over pelvis.","Move the limb without moving the trunk."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Holding breath to create fake stability.","Rib flare, hip shift, or spinal sag."]}'::jsonb),
  ('Mountain Climber Switch Freeze', 'mountain-climber-switch-freeze', 'Mountain Climber Switch Freeze is a neural-focused drill for limb exchange speed, anti-extension control, and hip flexor timing. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Fast plank-based hip switch with a freeze that trains trunk stiffness during rapid limb exchange.', 'Primary subrole: Activate. Neural emphasis: limb exchange speed, anti-extension control, and hip flexor timing. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Reflexive trunk control', 'prepare_and_access', 'activate', 'neural_activation', '{"primary_joint_actions":["hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination","trunk_bracing","rib_pelvis_stack"],"primary_tissues":["abdominals","obliques","diaphragm","glutes","hip_flexors","adductors","wrist_flexors","wrist_extensors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"dynamic","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"Perform Mountain Climber Switch Freeze as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Use a mat or clear floor area.","Athlete starts in the base position with ribs stacked over pelvis.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete sets the trunk first and breathes without bracing aggressively.","Move one limb or opposite limbs while the pelvis and ribcage stay quiet.","Pause briefly to show control before the next switch or tap.","End the set when hips rock, breath holding appears, or timing slows."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Ribs stacked over pelvis."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily.","Holding breath to create fake stability.","Rib flare, hip shift, or spinal sag."]}'::jsonb),
  ('A-March Linear', 'a-march-linear', 'A-March Linear is a neural-focused drill for sprint posture, opposite arm-leg timing, and ground contact awareness. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Marching sprint-mechanics drill that maps posture, arm timing, and front-side rhythm at low cost.', 'Primary subrole: Locomotion / Sprint Mechanics. Neural emphasis: sprint posture, opposite arm-leg timing, and ground contact awareness. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Sprint coordination', 'movement_intelligence', 'locomotion_sprint_mechanics', 'neural_sprint_mechanics', '{"primary_joint_actions":["hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination"],"primary_tissues":["nervous_system","postural_system","glutes","hip_flexors","adductors","calves","achilles_tendon","foot_intrinsics"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"dynamic","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Perform A-March Linear as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Use a clear, non-slippery training lane.","Athlete starts in the base position with posture organized and attention on the cue.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete starts organized and attentive.","Perform the pattern at the assigned rhythm or speed.","Own the finish position before the next repetition.","Stop before fatigue changes timing, posture, or coordination."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily."]}'::jsonb),
  ('A-Skip Snap Down', 'a-skip-snap-down', 'A-Skip Snap Down is a neural-focused drill for elastic rhythm, ground stiffness, and front-side sprint timing. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 3, 15, 60, 75, 'Rhythmic sprint skip that adds elastic foot contact and a crisp downstroke under the hip.', 'Primary subrole: Locomotion / Sprint Mechanics. Neural emphasis: elastic rhythm, ground stiffness, and front-side sprint timing. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Sprint coordination', 'movement_intelligence', 'locomotion_sprint_mechanics', 'neural_sprint_mechanics', '{"primary_joint_actions":["hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination","hip_knee_ankle_absorption","eccentric_braking","postural_stick"],"primary_tissues":["nervous_system","postural_system","calves","achilles_tendon","foot_intrinsics","plantar fascia","glutes","hip_flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"dynamic","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"Perform A-Skip Snap Down as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Use a clear, non-slippery training lane.","Athlete starts in the base position with posture organized and attention on the cue.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete loads quietly with posture stacked and eyes forward.","Athlete performs the jump, hop, contact, or drop with crisp intent.","Athlete sticks, rebounds, or finishes exactly as assigned without extra contacts.","Stop the set if contact sound, alignment, or rhythm degrades."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Quiet contacts."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily.","Landing loud or stiff.","Knees collapsing inward or feet spinning out."]}'::jsonb),
