  ('Reactive 45-Degree Cut', 'reactive-45-degree-cut', 'Reactive 45-Degree Cut is a neural-focused drill for visual cue reading, cut angle control, and quick re-acceleration. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 3, 3, 15, 90, 105, 'Coach-cued 45-degree cut that combines reaction, braking, and re-acceleration at a controlled dose.', 'Primary subrole: Reactive Agility Output. Neural emphasis: visual cue reading, cut angle control, and quick re-acceleration. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Reactive cut', 'output', 'reactive_agility_tumbling_output', 'reactive_agility_output', '{"primary_joint_actions":["hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination","hip_knee_ankle_absorption","eccentric_braking","postural_stick"],"primary_tissues":["nervous_system","postural_system","glutes","hip_flexors","adductors","quadriceps","patellar_tendon","calves"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"controlled_between_reps","balance_demand":"dynamic","coordination_demand":"high","impact_level":2}'::jsonb, '{"movement_description":"Perform Reactive 45-Degree Cut as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Set cones to mark a short, clear lane or decision area.","Keep distances short enough that every rep can be sharp and controlled.","Complete general warm-up first; do not start this cold or under fatigue."],"execution_steps":["Athlete holds the start position and waits for the cue instead of guessing.","Coach or partner gives one clear visual or auditory cue.","Athlete makes the correct first movement, finishes the required action, and regains control.","Reset fully before the next rep so attention and mechanics stay crisp."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Quiet contacts."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily.","Landing loud or stiff.","Knees collapsing inward or feet spinning out."]}'::jsonb),
  ('Reactive Med Ball Toss and Relocate', 'reactive-med-ball-toss-and-relocate', 'Reactive Med Ball Toss and Relocate is a neural-focused drill for throw-then-move timing, relocation footwork, and reactive catching posture. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Light med-ball partner drill that links throw accuracy, relocation, and catch readiness.', 'Primary subrole: Perception-Action / Reactive Movement. Neural emphasis: throw-then-move timing, relocation footwork, and reactive catching posture. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Reactive throw and relocate', 'movement_intelligence', 'perception_action_reactive_movement', 'perception_action_skill', '{"primary_joint_actions":["thoracic_rotation","hip_rotation","trunk_rotation_control","hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination","trunk_bracing"],"primary_tissues":["nervous_system","postural_system","abdominals","obliques","diaphragm","deltoids","rotator_cuff","scapular_stabilizers"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"dynamic","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Perform Reactive Med Ball Toss and Relocate as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Use a light medicine ball the athlete can move without strain.","Set a partner, wall, or target location with enough space for a controlled reset.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete holds the start position and waits for the cue instead of guessing.","Coach or partner gives one clear visual or auditory cue.","Athlete makes the correct first movement, finishes the required action, and regains control.","Reset fully before the next rep so attention and mechanics stay crisp."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Ribs stacked over pelvis."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily.","Holding breath to create fake stability.","Rib flare, hip shift, or spinal sag."]}'::jsonb),
  ('Split-Stance Crossover Chase', 'split-stance-crossover-chase', 'Split-Stance Crossover Chase is a neural-focused drill for visual reaction, crossover projection, and short chase acceleration. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 3, 3, 8, 75, 90, 'Split-stance crossover start that turns a partner cue into a short chase and controlled finish.', 'Primary subrole: Acceleration Start Speed. Neural emphasis: visual reaction, crossover projection, and short chase acceleration. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Reactive acceleration', 'output', 'acceleration_start_speed', 'neural_output_reaction_speed', '{"primary_joint_actions":["hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination","thoracic_rotation","hip_rotation","trunk_rotation_control"],"primary_tissues":["nervous_system","postural_system","glutes","hip_flexors","adductors","calves","achilles_tendon","abdominals"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"controlled_between_reps","balance_demand":"dynamic","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"Perform Split-Stance Crossover Chase as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Set cones to mark a short, clear lane or decision area.","Keep distances short enough that every rep can be sharp and controlled.","Complete general warm-up first; do not start this cold or under fatigue."],"execution_steps":["Athlete starts organized and attentive.","Perform the pattern at the assigned rhythm or speed.","Own the finish position before the next repetition.","Stop before fatigue changes timing, posture, or coordination."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Turn with control, not a twist and collapse."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily."]}'::jsonb),
  ('Low-Level Reactive Agility Box', 'low-level-reactive-agility-box', 'Low-Level Reactive Agility Box is a neural-focused drill for multi-cue scanning, short-range movement choice, and controlled reset. It gives the athlete a short, crisp exposure that improves readiness, timing, perception, or output without becoming conditioning.', 'BEGINNER', 8, 2, 3, 15, 60, 75, 'Small-box reactive movement drill that trains scan, choose, move, brake, and reset without conditioning intent.', 'Primary subrole: Perception-Action / Reactive Movement. Neural emphasis: multi-cue scanning, short-range movement choice, and controlled reset. Coach it as a high-quality nervous-system exposure: short sets, precise positions, full attention, and enough rest that every rep remains fast or controlled.', 'Fast signal, clean answer. Move with intent, stay relaxed where you can, and own the finish.', 'Reactive agility', 'movement_intelligence', 'perception_action_reactive_movement', 'perception_action_skill', '{"primary_joint_actions":["hip_flexion_extension","knee_drive","ankle_stiffness","arm_leg_coordination","hip_knee_ankle_absorption","eccentric_braking","postural_stick","thoracic_rotation"],"primary_tissues":["nervous_system","postural_system","glutes","hip_flexors","adductors","calves","achilles_tendon","abdominals"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"rhythmic","balance_demand":"dynamic","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"Perform Low-Level Reactive Agility Box as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Set cones to mark a short, clear lane or decision area.","Keep distances short enough that every rep can be sharp and controlled.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete holds the start position and waits for the cue instead of guessing.","Coach or partner gives one clear visual or auditory cue.","Athlete makes the correct first movement, finishes the required action, and regains control.","Reset fully before the next rep so attention and mechanics stay crisp."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Quiet contacts."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily.","Landing loud or stiff.","Knees collapsing inward or feet spinning out."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
